patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..30bbc45976aa 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1367,6 +1367,173 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     }
   }

+  // Handle case where one side is (and X, Mask) and the other is X.
+  // E.g. (icmp ult X, C) & (icmp eq (and X, Mask), Val)
+  // If all values X satisfying (and X, Mask) == Val also satisfy the other
+  // comparison, we can drop the other comparison.
+  if (V1 != V2) {
+    Value *X;
+    const APInt *Mask, *Val;
+    ICmpInst::Predicate PredX;
+    const APInt *CX;
+    ICmpInst *MaskedICmp;
+    ICmpInst::Predicate PredMasked;
+    const APInt *CMasked;
+
+    // Try: V1 = X, V2 = (and X, Mask) with Pred2 being EQ/NE
+    //      or V2 = X, V1 = (and X, Mask) with Pred1 being EQ/NE
+    if (match(V2, m_And(m_Specific(V1), m_APInt(Mask))) &&
+        ICmpInst::isEquality(Pred2)) {
+      X = V1; PredX = Pred1; CX = C1;
+      MaskedICmp = ICmp2; PredMasked = Pred2; CMasked = C2;
+    } else if (match(V1, m_And(m_Specific(V2), m_APInt(Mask))) &&
+               ICmpInst::isEquality(Pred1)) {
+      X = V2; PredX = Pred2; CX = C2;
+      MaskedICmp = ICmp1; PredMasked = Pred1; CMasked = C1;
+    } else {
+      return nullptr;
+    }
+
+    // Canonical form requires Val & Mask == Val
+    if ((*CMasked & *Mask) != *CMasked)
+      return nullptr;
+
+    // Only handle masks where the unmasked bits form a contiguous low range,
+    // i.e., the mask is a negated power of two (e.g., -2, -4, -8, ...).
+    // Otherwise the set of values satisfying (X & Mask) == Val is not a
+    // single contiguous block and the range analysis below does not apply.
+    if (!Mask->isNegatedPowerOf2())
+      return nullptr;
+
+    APInt MinX = *CMasked;
+    APInt MaxX = *CMasked | ~(*Mask);
+
+    // Helper to check unsigned implication.
+    // When IsImpliedCheck is true: checks if all masked values satisfy PredX.
+    // When IsImpliedCheck is false: checks if no masked value satisfies PredX.
+    auto CheckUnsignedImplied = [&](bool IsImpliedCheck) -> bool {
+      switch (PredX) {
+      case ICmpInst::ICMP_ULT:
+        return IsImpliedCheck ? MaxX.ult(*CX) : MinX.uge(*CX);
+      case ICmpInst::ICMP_ULE:
+        return IsImpliedCheck ? MaxX.ule(*CX) : MinX.ugt(*CX);
+      case ICmpInst::ICMP_UGT:
+        return IsImpliedCheck ? MinX.ugt(*CX) : MaxX.ule(*CX);
+      case ICmpInst::ICMP_UGE:
+        return IsImpliedCheck ? MinX.uge(*CX) : MaxX.ult(*CX);
+      default:
+        return false;
+      }
+    };
+
+    // Helper to check signed implication.
+    auto CheckSignedImplied = [&](bool IsImpliedCheck) -> bool {
+      switch (PredX) {
+      case ICmpInst::ICMP_SLT:
+        // All masked values < CX if MaxX < CX (signed)
+        return IsImpliedCheck ? MaxX.slt(*CX) : MinX.sge(*CX);
+      case ICmpInst::ICMP_SLE:
+        return IsImpliedCheck ? MaxX.sle(*CX) : MinX.sgt(*CX);
+      case ICmpInst::ICMP_SGT:
+        // All masked values > CX if MinX > CX (signed)
+        return IsImpliedCheck ? MinX.sgt(*CX) : MaxX.sle(*CX);
+      case ICmpInst::ICMP_SGE:
+        return IsImpliedCheck ? MinX.sge(*CX) : MaxX.slt(*CX);
+      default:
+        return false;
+      }
+    };
+
+    // Check if all masked values satisfy the range check (masked => range)
+    bool MaskedImpliesRange =
+        CheckUnsignedImplied(/*IsImpliedCheck=*/true) ||
+        CheckSignedImplied(/*IsImpliedCheck=*/true);
+    // Check if no masked value satisfies the range check (disjoint)
+    bool MaskedDisjointFromRange =
+        CheckUnsignedImplied(/*IsImpliedCheck=*/false) ||
+        CheckSignedImplied(/*IsImpliedCheck=*/false);
+
+    if (IsAnd && PredMasked == ICmpInst::ICMP_EQ) {
+      // (icmp eq (and X, Mask), Val) & (icmp pred X, C)
+      if (MaskedImpliesRange)
+        return MaskedICmp;
+      if (MaskedDisjointFromRange)
+        return ConstantInt::getFalse(ICmp1->getType());
+
+      // If the range check is unsigned less-than and the only masked value
+      // in range is Val itself, we can simplify to X == Val.
+      if (PredX == ICmpInst::ICMP_ULT || PredX == ICmpInst::ICMP_SLT) {
+        APInt Step = ~(*Mask) + 1;
+        APInt NextVal = *CMasked + Step;
+        // If the next value satisfying the mask is outside the range,
+        // then Val is the only one in range, so X must equal Val.
+        if ((PredX == ICmpInst::ICMP_ULT && NextVal.uge(*CX)) ||
+            (PredX == ICmpInst::ICMP_SLT && NextVal.sge(*CX))) {
+          // Val must also be within the range
+          if ((PredX == ICmpInst::ICMP_ULT && CMasked->ult(*CX)) ||
+              (PredX == ICmpInst::ICMP_SLT && CMasked->slt(*CX))) {
+            return Builder.CreateICmp(ICmpInst::ICMP_EQ, X,
+                                      ConstantInt::get(X->getType(), *CMasked));
+          }
+          // Val is not in range, disjoint
+          return ConstantInt::getFalse(ICmp1->getType());
+        }
+      }
+    }
+    if (!IsAnd && PredMasked == ICmpInst::ICMP_EQ) {
+      // (icmp eq (and X, Mask), Val) | (icmp pred X, C)
+      // If the range check and the masked check together cover a contiguous
+      // range, we can merge them into a single range check.
+      if (PredX == ICmpInst::ICMP_ULT) {
+        // Range: [0, CX-1], Masked block: [MinX, MaxX]
+        // If they overlap or touch, the union is [0, max(CX-1, MaxX)].
+        if (CX->ugt(*CMasked)) {
+          // Masked block starts within or touches the range.
+          // The union covers [0, max(CX-1, MaxX)].
+          APInt NewCX = MaxX + 1;
+          if (NewCX.ugt(MaxX)) { // No overflow
+            if (NewCX != *CX)
+              return Builder.CreateICmp(ICmpInst::ICMP_ULT, X,
+                                        ConstantInt::get(X->getType(), NewCX));
+            // If NewCX == CX, the masked block is entirely within range,
+            // so the masked check is redundant. Return the range check.
+            return ICmp1->getOperand(0) == X ? ICmp1 :
+                   ICmp2->getOperand(0) == X ? ICmp2 : nullptr;
+          }
+        }
+      }
+    }
+
+
+    if (IsAnd && PredMasked == ICmpInst::ICMP_NE) {
+      // (icmp ne (and X, Mask), Val) & (icmp pred X, C)
+      // E.g. X > C & (X & Mask) != Val can merge into a larger range.
+      if (PredX == ICmpInst::ICMP_UGT) {
+        // Range: X > CX (X >= CX+1)
+        // Masked: (X & Mask) != Val
+        // If the excluded values (X & Mask) == Val are all within the range
+        // and can be "punched out" to form a larger range, do so.
+        // Specifically, if CX+1 == MinX (the excluded range starts right after
+        // the range lower bound), we can lift the lower bound to MaxX+1.
+        APInt RangeStart = *CX + 1;
+        if (RangeStart == *CMasked && CMasked->ult(MaxX)) {
+          // Excluded range is [CMasked, MaxX]. We want X > MaxX.
+          APInt NewCX = MaxX;
+          // Only if NewCX > *CX (otherwise no change)
+          if (NewCX.ugt(*CX)) {
+            return Builder.CreateICmp(ICmpInst::ICMP_UGT, X,
+                                      ConstantInt::get(X->getType(), NewCX));
+          }
+        }
+      }
+    }
+
+    return nullptr;
+  }
+
+  if (V1 != V2)
+    return nullptr;
+
   if (V1 != V2)
     return nullptr;

